    return UserData(
      userId: userId,
      email: email,
      name: name,
    );
  }

  Future<bool> isLoggedIn() async {
    final prefs = await SharedPreferences.getInstance();
    final isLoggedIn = prefs.getBool(_isLoggedInKey) ?? false;
    
    if (!isLoggedIn) return false;

    final accessToken = await getAccessToken();
